+import type { Trait } from '../trait/types';
+import type { World } from '../world';
+import { $aspect } from './symbols';
+import type { Aspect, AspectRecord, AspectValue } from './types';
+
+let aspectId = 0;
+
+export function isAspect(value: unknown): value is Aspect {
+    return !!(value as Aspect | undefined)?.[$aspect];
+}
+
+export function createAspect<T extends readonly [Trait, Trait, ...Trait[]]>(
+    ...inputs: T
+): Aspect<FlattenAspects<T>> {
+    const traits = inputs.flatMap((input) => (isAspect(input) ? input.traits : [input])) as FlattenAspects<T>;
+    const fields = new Set<string>();
+    const schema: Record<string, unknown> = {};
+
+    for (const trait of traits) {
+        if (trait[$internal].relation || isRelation(trait as never)) {
+            throw new Error('Koota: Relations cannot be constituents of an aspect.');
+        }
+        for (const key of Object.keys(trait.schema)) {
+            if (fields.has(key)) throw new Error(`Koota: Aspect field "${key}" is defined more than once.`);
+            fields.add(key);
+            schema[key] = (trait.schema as Record<string, unknown>)[key];
+        }
+    }
+
+    const aspect = Object.assign(
+        (params: AspectValue<FlattenAspects<T>> = {}) => [aspect, params] as [Aspect<FlattenAspects<T>>, AspectValue<FlattenAspects<T>>],
+        { [$aspect]: true as const, id: aspectId++, traits: Object.freeze(traits), schema: Object.freeze(schema) }
+    ) as Aspect<FlattenAspects<T>>;
+    return Object.freeze(aspect);
+}
+
+type FlattenOne<T> = T extends Aspect<infer U> ? U[number] : T;
+export type FlattenAspects<T extends readonly (Trait | Aspect)[]> = {
+    [K in keyof T]: FlattenOne<T[K]>;
+};
+
+export function hasAspect(world: World, entity: Entity, aspect: Aspect): boolean {
+    return aspect.traits.every((trait) => hasTrait(world, entity, trait));
+}
+
+export function getAspect<T extends readonly Trait[]>(world: World, entity: Entity, aspect: Aspect<T>) {
+    if (!hasAspect(world, entity, aspect)) return undefined;
+    return aspect.traits.reduce((result, trait) => Object.assign(result, getTrait(world, entity, trait)), {}) as AspectRecord<T>;
+}
+
+function valuesForTrait(aspect: Aspect, trait: Trait, value: Record<string, unknown>) {
+    const result: Record<string, unknown> = {};
+    for (const key of Object.keys(trait.schema)) if (key in value) result[key] = value[key];
+    return result;
+}
+
+export function addAspect(world: World, entity: Entity, aspect: Aspect, value: Record<string, unknown> = {}) {
+    for (const trait of aspect.traits) {
+        if (!hasTrait(world, entity, trait)) addTrait(world, entity, [trait, valuesForTrait(aspect, trait, value)]);
+    }
+}
+
+export function removeAspect(world: World, entity: Entity, aspect: Aspect) {
+    for (const trait of aspect.traits) removeTrait(world, entity, trait);
+}
+
+export function setAspect(world: World, entity: Entity, aspect: Aspect, value: Record<string, unknown>, triggerChanged = true) {
+    for (const trait of aspect.traits) {
+        const fields = valuesForTrait(aspect, trait, value);
+        if (Object.keys(fields).length) setTrait(world, entity, trait, fields, triggerChanged);
+    }
+}
