+        if (isModifier(param)) {
+            if (param.type === 'not') return [];
+            return param.traits.filter((trait) => trait[$internal].type !== 'tag').map((trait) => trait[$internal].get(getEntityId(entity), getStore(world, trait)));
+        }
+        if (isRelationPair(param)) return [];
